#include <cmath>
#include <cstdio>
#include <iostream>
using namespace std;

//Borwein's algorithm
//gionuno

typedef long double ld;

ld quad_convergence(int T)
{
	ld a0 = sqrt(2.0);
	ld b0 = 0.0;
	ld p0 = 2.0+a0;
	for(int n=0;n<T;n++)
	{
		ld sa = sqrt(a0);
		ld an = 0.5*(sa+1./sa);
		ld bn = (1.0+b0)*sa/(a0+b0);
		ld pn = (1.0+an)*p0*bn/(1.0+bn);
		a0 = an;
		b0 = bn;
		p0 = pn;
	}	
	return p0;
}

int main()
{
	cout.precision(17);
	cout << "pi approx " << fixed << quad_convergence(20) << endl;
	return 0;
}

/**

 **  Java Program to Implement Borwein Algorithm

 **/

import java.util.Scanner;



/** Class Borwein **/

public class Borwein

{

    /** compute 1/pi **/

    public double getOneByPi(int k)

    {

        double ak = 6.0 - 4 * Math.sqrt(2);

        double yk = Math.sqrt(2) - 1.0;



        double ak1 ;

        double yk1 ;

        for (int i = 0; i < k; i++)

        {

            yk1 = (1 - Math.pow((1 - yk * yk * yk * yk),(0.25)))/(1 + Math.pow((1 - yk * yk * yk * yk),(0.25)));

            ak1 = ak * Math.pow((1 + yk1), 4) - Math.pow(2, 2 * i + 3) * yk1 * (1 + yk1 + yk1 * yk1);

            yk = yk1;

            ak = ak1;

        }

        return ak;

    }

    /** Main function **/

    public static void main (String[] args)

    {

        Scanner scan = new Scanner(System.in);

        System.out.println("Borwein 1/Pi Algorithm Test\n");

        /** Make an object of Borwein class **/

        Borwein b = new Borwein();



        System.out.println("Enter number of iterations ");

        int k = scan.nextInt();



        System.out.println("\nValue of 1/pi : "+ b.getOneByPi(k));

    }

}
